#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

// 检查字符串是否为回文
bool isPalindrome(const string& str) {
    int left = 0;
    int right = str.size() - 1;
    while (left < right) {
        if (str[left] != str[right]) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}

int main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        string s;
        cin >> s;
        bool found = false;
        for (int j = 1; j < s.size(); j++) {
            string s1 = s.substr(0, j);
            string s2 = s.substr(j);
            if (isPalindrome(s1) && isPalindrome(s2)) {
                cout << "Yes" << endl;
                found = true;
                break;
            }
        }
        if (!found) {
            cout << "No" << endl;
        }
    }
    return 0;
}
